import * as React from 'react';
import { graphql, navigate } from 'gatsby';
import { GatsbyImage, getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Typography from '@mui/material/Typography';
import { Layout } from '../components/layout';
import { Link } from '../components/common/link';
import { Seo } from '../components/seo';
import { Navigation } from '../components/navigation';
import { isExistId, idToLabel } from '../libs/categories';
import { works } from '../libs/works';

const Work = props => {
  const { data, pageContext } = props;

  const [category, setCategory] = React.useState('all');

  const { html, frontmatter } = pageContext.work;
  const { slug } = frontmatter;

  const images = data.allFile.edges
    .filter(({ node }) => !/^.*_00$/.test(node.name))
    .map(({ node }) => getImage(node));

  const _works = works.filter(work => {
    if (category !== 'all') {
      // カテゴリーが指定されている場合は一致するもののみ抽出
      if (Array.isArray(work.category)) {
        return work.category.includes(category);
      } else {
        return work.category === category;
      }
    } else {
      // カテゴリ未指定時は全てのアイテムを返す
      return true;
    }
  });

  const currentIndex = _works.findIndex(({ link }) => `/${link}` === slug);

  const nextIndex = (currentIndex + 1) % _works.length;
  const prevIndex = currentIndex === 0 ? _works.length - 1 : currentIndex - 1;

  const currentData = _works[currentIndex];
  const nextData = _works[nextIndex];
  const prevData = _works[prevIndex];

  const prevLink = `/works/${prevData?.link}/${
    category ? `?category=${category}` : ''
  }`;
  const nextLink = `/works/${nextData?.link}/${
    category ? `?category=${category}` : ''
  }`;
  const categoryLink = '/works/' + (category ? `?category=${category}` : '');

  const videos = currentData?.videos;

  React.useEffect(() => {
    const param = new URLSearchParams(props.location.search);
    const category = param.get('category');
    if (isExistId(category)) {
      setCategory(category);
    }
  }, [props.location.search]);

  return (
    <Layout>
      <Navigation />
      <Box py={10}>
        <Grid container justifyContent='center' spacing={4}>
          {videos?.map((videoId, i) => (
            <Grid item xs={12} key={i}>
              <Box display='flex' justifyContent='center' alignItems='center'>
                <iframe
                  width={395}
                  height={702}
                  src={
                    `https://www.youtube.com/embed/${videoId}?` +
                    [
                      'controls=1',
                      'rel=0',
                      'autoplay=1',
                      'modestbranding=1'
                    ].join('&')
                  }
                  title={currentData.title}
                  frameBorder={0}
                  allow='accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share'
                  referrerPolicy='strict-origin-when-cross-origin'
                  allowFullScreen
                />
              </Box>
            </Grid>
          ))}
          {images.map((image, i) => {
            // [NOTE]: GatsbyImage の圧縮により 1920:1918 のようなパターンが発生したため
            // ポートレート判定に含みを持たせるため 1.1 と比較
            // const isPortrait = image.width <= image.height;
            const isPortrait = image.width / image.height <= 1.1;
            const floatWidth = isPortrait ? '50%' : '75%';

            return (
              <Grid item xs={12} key={i}>
                <Box
                  sx={{
                    width: {
                      md: floatWidth,
                      sm: '100%',
                      xs: '100%'
                    },
                    mx: 'auto',
                    pointerEvents: 'none',
                    userSelect: 'none'
                  }}
                  onClick={e => e.preventDefault()}
                  onMouseDown={e => e.preventDefault()}
                  onMouseUp={e => e.preventDefault()}
                  onContextMenu={e => {
                    e.preventDefault();
                  }}
                >
                  <GatsbyImage
                    image={image}
                    alt={`image-${i}`}
                    style={{
                      pointerEvents: 'none',
                      userSelect: 'none'
                    }}
                  />
                </Box>
              </Grid>
            );
          })}

          <Grid item xs={12} mb={4}>
            <div dangerouslySetInnerHTML={{ __html: html }} />
            <Typography
              sx={{ letterSpacing: '0.25rem', textAlign: 'center' }}
              dangerouslySetInnerHTML={{
                __html: currentData?.title
              }}
            />
            <Typography
              sx={{ mt: 2, textAlign: 'center' }}
              dangerouslySetInnerHTML={{
                __html: currentData?.description
              }}
            />
          </Grid>

          <Grid item xs={6}>
            <Box>
              <Link
                href={prevLink}
                onClick={e => {
                  e.preventDefault();
                  navigate(prevLink);
                }}
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'start'
                }}
              >
                &lt;
                <Typography
                  variant='body2'
                  align='left'
                  sx={{
                    ml: 1,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}
                >
                  {prevData?.title.replace('<br />', ' ')}
                </Typography>
              </Link>
            </Box>
          </Grid>
          <Grid item xs={6}>
            <Box>
              <Link
                href={nextLink}
                onClick={e => {
                  e.preventDefault();
                  navigate(nextLink);
                }}
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'end'
                }}
              >
                <Typography
                  variant='body2'
                  align='right'
                  sx={{
                    mr: 1,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}
                >
                  {nextData?.title.replace('<br />', ' ')}
                </Typography>
                &gt;
              </Link>
            </Box>
          </Grid>

          <Grid item xs={12}>
            <Box
              sx={{
                display: 'flex',
                justifyContent: 'center'
              }}
            >
              <Link
                href={categoryLink}
                onClick={e => {
                  e.preventDefault();
                  navigate(categoryLink);
                }}
              >
                <Typography variant='body2'>
                  Back to "{category ? idToLabel(category) : 'All'}"
                </Typography>
              </Link>
            </Box>
          </Grid>
        </Grid>
      </Box>
    </Layout>
  );
};

export default Work;

export const data = graphql`
  query Query($imagePathReg: String) {
    allFile(
      sort: { relativePath: ASC }
      filter: {
        relativeDirectory: { eq: "works" }
        name: { regex: $imagePathReg }
      }
    ) {
      edges {
        node {
          relativeDirectory
          childImageSharp {
            gatsbyImageData(width: 1920)
          }
          name
        }
      }
    }
  }
`;

export const Head = ({ pageContext }) => {
  const { slug } = pageContext.work.frontmatter;

  const currentIndex = works.findIndex(({ link }) => `/${link}` === slug);

  const title = works[currentIndex]?.title.replace('<br />', ' ') || '';

  return <Seo title={title} />;
};
